  ('elementary-7fec267e-moex-00214', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '依據公民投票法之規定，下列敘述何者正確？', '["公民投票涉及原住民族權利者，不得違反原住民族基本法之規定", "公民投票僅限於全國性公民投票，地方自治團體不得舉辦地方性公民投票", "立法院基於責任政治之要求，不得提案舉辦公民投票", "經複決廢止之法律，立法機關仍得於1年後再制定相同之法律"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00215', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '依據公職人員選舉罷免法之規定，下列何者具有候選人登記資格？', '["現於區公所服替代役之役男", "私立大學碩士班之在籍學生", "曾犯貪污罪而受緩刑宣告者", "受破產宣告確定而尚未復權者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00216', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '依據臺灣地區與大陸地區人民關係條例之規定，若大陸地區人民未經許可進入臺灣地區，由下列何機關執 行強制出境作業？', '["內政部移民署", "內政部警政署", "行政院大陸委員會", "海洋委員會海巡署"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00217', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '民主國家對於政府應擔負服務人民的角色有不同的期許，下列何者是最基本的民主價值，也是有限政府應 從事的作為？', '["充分保障私有財產權", "有免費疫苗可以施打", "就讀高等教育免學費", "控制物價與通貨膨脹"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00218', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '某國國會眾議院大選剛落幕，現任總理所屬的執政黨「不滿公民行動」痛失第一大黨地位，兩大反對聯盟 「一起」和「海盜和市長」合計席次過半，已宣布合作組閣，產生新的政府。該國應屬於那種政府體制？', '["內閣制", "總統制", "混合制", "委員會制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00219', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '甲借錢給設籍高雄但久居新北市某公寓的乙，乙未依約定即時還款並有持續拖延之傾向，請問甲該如何救 濟其權利？', '["僅得向高雄地方法院提起民事訴訟", "訴訟前應先向調解委員會申請調解", "甲乙於法院審理中得成立和解方案", "甲必須聘請律師方可提出民事訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00220', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '下列四則新聞標題，何者合乎相關法規？', '["被告欲繳罰金，檢察官拒絕易科罰金並發監執行", "酒駕犯獲緩起訴，民眾抨擊法官縱容酒駕", "酒測值誤差獲無罪，公設辯護人為酒駕被害人上訴", "正義波麗士，熱血員警為被害人提出公訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00221', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '有民眾攜帶寵物蛇搭乘自強號，寵物蛇爬行到車廂屋頂處造成乘客恐慌。嗣後臺鐵表示要依法追究飼主之 責任，並依據法律對行為違反規定的飼主施以處罰，其處罰性質與下列選項何者相同？', '["因故意或過失，不法侵害他人之權利者", "擅自以公開播送方法侵害他人之著作財產權者", "私行拘禁或以其他非法方法，剝奪人之行動自由者", "因違反鐵路法規而處以罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00222', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '依司法院大法官解釋，關於集會遊行自由，下列敘述何者正確？', '["群眾因特殊原因未經召集自發聚集之偶發性集會遊行，自然無法事先申請許可，因此集會遊行法的事前 許可制，應排除於偶發性集會遊行之適用", "集會遊行法針對一般集會遊行仍採取事前許可制，已嚴重侵害人民之集會遊行自由而屬於違憲", "集會遊行是人民表達自身訴求的重要手段，因此縱使是國家針對無關集會遊行內容與目的之時間、地點 及方式進行限制，也必須受嚴格審查", "為使主管機關得以保障人民權利，並降低集會遊行對社會秩序之影響，因此緊急性集會遊行仍須於 24 小時前進行事前申請，並無違反憲法意旨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00223', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '國家為一定政策目標之需要，對於有特定關係之國民所課徵，並將課徵所得之金錢建立特別基金，專供該 特定目標達成。此種公法上負擔，學理上稱為：', '["怠金", "國債", "特別公課", "間接稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
